14	template<std::size_t BusWidth>
15	class SimpleMemory : public sc_core::sc_module
16	{
17	public:
18	  static constexpr uint64_t INVALID_ADDRESS = 0xffffffffffffffff;
19	
20	  const MemoryRegion region;
21	  const MemoryRegion alias_region;
22	
23	private:
24	  std::vector<uint8_t> owned_storage_;
25	
26	public:
27	  // `data` aliases either `owned_storage_` (default) or an externally supplied
28	  // buffer (e.g. an mmap of a shared file). All read/write paths go through
29	  // this span so the backing choice is invisible to call sites.
30	  std::span<uint8_t> data;
31	
32	  unsigned latency = 1;
33	  tlm_utils::simple_target_socket<SimpleMemory<BusWidth>, BusWidth> socket{
34	    "tsck"};
35	
36	  // If `external_buffer` is empty, owned storage is allocated. Otherwise the
37	  // buffer must outlive this object and be at least as large as the region;
38	  // hybrid mode passes an mmap of a shared file here.
39	  SimpleMemory(const sc_core::sc_module_name& name,
40	               const MemoryRegion& region,
41	               const MemoryRegion& alias_region = {INVALID_ADDRESS,
42	                                                   INVALID_ADDRESS},
43	               std::span<uint8_t> external_buffer = {})
44	      : sc_core::sc_module{name},
45	        region(region),
46	        alias_region(alias_region),
47	        owned_storage_(external_buffer.empty()
48	                         ? std::vector<uint8_t>(region.end_address
49	                                                - region.base_address)
50	                         : std::vector<uint8_t>{}),
51	        data(external_buffer.empty() ? std::span<uint8_t>{owned_storage_}
52	                                     : external_buffer)
53	  {
54	    if (!external_buffer.empty()
55	        && external_buffer.size() < region.end_address - region.base_address)
56	        [[unlikely]]
57	      throw std::runtime_error(
58	        "SimpleMemory external_buffer smaller than region size");
59	    this->socket.register_b_transport(this, &SimpleMemory::b_transport);
60	  }
61	
62	  void b_transport(tlm::tlm_generic_payload& trans, sc_core::sc_time& delay)
63	  {
64	    auto cycles = handle_trans(trans);
65	    if (trans.get_response_status() == tlm::TLM_INCOMPLETE_RESPONSE)
66	      trans.set_response_status(tlm::TLM_OK_RESPONSE);
67	    delay += sc_core::sc_time(cycles, sc_core::SC_NS);
68	  }
69	
70	private:
71	  auto handle_trans(tlm::tlm_generic_payload& trans) -> unsigned
72	  {
73	    const auto addr = trans.get_address();
74	    const auto len = trans.get_data_length();
75	    const auto ptr = trans.get_data_ptr();
76	    const auto byte_enable_len = trans.get_byte_enable_length();
77	    const auto byte_enable_ptr = trans.get_byte_enable_ptr();
78	
79	    spdlog::debug("mem: {}, addr={:#x}, len={}",
80	                  trans.is_read() ? "read" : "write", addr, len);
81	
82	    uint64_t offset;
83	    if (region.contains({addr, addr + len})) [[likely]] {
84	      offset = addr - this->region.base_address;
85	    } else if (alias_region.contains({addr, addr + len})) {
86	      offset = addr - this->alias_region.base_address;
87	    } else {
88	      spdlog::error(
89	        "transaction is out of bounds of memory region [{:#x}-{:#x}]",
90	        this->region.base_address, this->region.end_address);
91	      trans.set_response_status(tlm::TLM_ADDRESS_ERROR_RESPONSE);
92	      return latency;
93	    }
94	    const auto buf = std::span{ptr, ptr + len};
95	    if (trans.is_read()) [[likely]] {
96	      std::copy_n(this->data.begin() + offset, len, buf.begin());
97	      return latency;
98	    }
99	
100	    if (!trans.is_write()) [[unlikely]] {
101	      throw std::runtime_error("unimplemented");
102	    }
103	
104	    // write operation
105	    if (byte_enable_len == 0) [[likely]] {
106	      std::copy_n(buf.begin(), len, this->data.begin() + offset);
107	      return latency;
108	    }
109	
110	    // handle byte strobe if needed
111	    // AXI/AHB may split an un-aligned write into multiple aligned writes
112	    // with byte enable mask
113	    assert(byte_enable_len == len);
114	    for (unsigned i = 0; i < len; i++) {
115	      if (byte_enable_ptr[i] == 0xff)
116	        this->data[offset + i] = buf[i];
117	    }
118	    return latency;
119	  }
120	};
