364	        }
365	      }
366	      sim.context_config = {args.save_ctx, args.continue_ctx, args.context_dir};
367	    }
368	
369	    sim.reset();
370	
371	    const int exit_code = sim.run();
372	
373	    sim.cpu.final();
374	
375	    const auto t1 = std::chrono::steady_clock::now();
376	    const auto cycles = sim.get_cycles();
377	    spdlog::info("{} cycles simulated", cycles);
378	    if (cycles > 0) {
379	      const auto ms =
380	        std::chrono::duration_cast<std::chrono::milliseconds>(t1 - t0);
